import { Box, Checkbox, FormControlLabel, FormGroup, Modal, Typography } from '@mui/material';
import React, { useEffect, useState } from 'react';
import { Genre } from '../../types/movies-grid.types';
import { useUserPreferences } from '../../context/user-preferences';

const mockGenres: Array<Genre> = [
	{
		id: 28,
		name: 'Action'
	},
	{
		id: 12,
		name: 'Adventure'
	},
	{
		id: 16,
		name: 'Animation'
	},
	{
		id: 35,
		name: 'Comedy'
	},
	{
		id: 80,
		name: 'Crime'
	},
	{
		id: 99,
		name: 'Documentary'
	},
	{
		id: 18,
		name: 'Drama'
	},
	{
		id: 10751,
		name: 'Family'
	},
	{
		id: 14,
		name: 'Fantasy'
	},
	{
		id: 36,
		name: 'History'
	},
	{
		id: 27,
		name: 'Horror'
	},
	{
		id: 10402,
		name: 'Music'
	},
	{
		id: 9648,
		name: 'Mystery'
	},
	{
		id: 10749,
		name: 'Romance'
	},
	{
		id: 878,
		name: 'Science Fiction'
	},
	{
		id: 10770,
		name: 'TV Movie'
	},
	{
		id: 53,
		name: 'Thriller'
	},
	{
		id: 10752,
		name: 'War'
	},
	{
		id: 37,
		name: 'Western'
	}
];

const style = {
	position: 'absolute' as const,
	top: '50%',
	left: '50%',
	transform: 'translate(-50%, -50%)',
	width: 800,
	height: 600,
	bgcolor: 'background.paper',
	border: '2px solid #000',
	boxShadow: 24,
	p: 4
};

const selectedGenresArray: Array<any> = [];

// function handleGenreSelection(checked: boolean, selectedGenre: Genre) {
// 	// commentary: reduce amount of parameters
// 	if (checked === true) {
// 		selectedGenresArray.push(selectedGenre);
// 	}
// 	if (checked === false) {
// 		const index = selectedGenresArray.indexOf(selectedGenre);
// 		selectedGenresArray.splice(index, 1);
// 	}

// 	return selectedGenresArray;
// }

function handleGenreSelection(checked: boolean, selectedGenre: Genre, setCheckedGenres: any) {
	setCheckedGenres((prevCheckedGenres: any) => ({
		...prevCheckedGenres,
		[selectedGenre.id]: checked
	}));
}

// function handleGenreSelectionButton(setGenres: any, setIsModalOpen: any, setIsChecked: any) {
// 	setGenres(selectedGenresArray);
// 	setIsModalOpen(false);
// 	setIsChecked(true);
// }

function handleGenreSelectionButton(setGenres: any, setIsModalOpen: any, setIsChecked: any, checkedGenres: any) {
	const selectedGenres = Object.keys(checkedGenres)
		.filter((id: any) => checkedGenres[id])
		.map(id => mockGenres.find(genre => genre.id === Number(id)));

	console.log('selectedGenres');
	console.log(selectedGenres);

	setGenres(selectedGenres);
	setIsModalOpen(false);
	setIsChecked(true);
}

function handleSelectedPreviously(genres: any, mockGenre: any) {
	genres.map((g: any) => {
		if (g.name === mockGenre.name) {
			return true;
		}
	});
	return false;
}

export default function StartModal() {
	const { setGenres, isModalOpen, setIsModalOpen, genres } = useUserPreferences();
	const [checkedGenres, setCheckedGenres] = useState<{ [id: number]: boolean }>({});
	const [isChecked, setIsChecked] = useState<boolean>(false);
	useEffect(() => {
		if (genres.length > 0) {
			const newCheckedGenres: { [id: number]: boolean } = {};
			genres.forEach(genre => {
				newCheckedGenres[genre.id] = true;
			});
			setCheckedGenres(newCheckedGenres);
		}
	}, [genres]);

	return (
		<div>
			<Modal open={isModalOpen} onClose={() => setIsModalOpen(false)} aria-labelledby="modal-modal-title" aria-describedby="modal-modal-description">
				<Box sx={style}>
					<Typography id="modal-modal-title" variant="h6" component="h2">
						Selecione suas preferências
					</Typography>
					<Typography id="modal-modal-description" sx={{ mt: 2 }}>
						Selecione no mínimo 3 e no máximo 5 opções de Gênero.
						<FormGroup>
							<div className="justify-center grid grid-cols-3 p-6">
								{/* {mockGenres.map((mockGenre, index) => {
									return (
										<FormControlLabel
											control={<Checkbox onClick={e => handleGenreSelection((e.target as HTMLInputElement).checked, mockGenre)} />}
											label={`${mockGenre.name}`}
											key={`check ${index}`}
										/>
									);
								})} */}
								{mockGenres.map((mockGenre, index) => (
									<FormControlLabel
										control={
											<Checkbox
												checked={!!checkedGenres[mockGenre.id]}
												onClick={e => handleGenreSelection((e.target as HTMLInputElement).checked, mockGenre, setCheckedGenres)}
											/>
										}
										label={`${mockGenre.name}`}
										key={`check ${index}`}
									/>
								))}
							</div>
							<button onClick={() => handleGenreSelectionButton(setGenres, setIsModalOpen, setIsChecked, checkedGenres)}>Confirmar</button>
						</FormGroup>
					</Typography>
				</Box>
			</Modal>
		</div>
	);
}
